  const [variantGroup2, setVariantGroup2] = useState({ name: 'Kích thước', values: [] as string[] });
  const [tempValue1, setTempValue1] = useState('');
  const [tempValue2, setTempValue2] = useState('');

  // Bulk Edit Variants State
