      const baseCost = formData.importPrice || 0;
      if (baseCost === 0) return 0;

      // Fixed Costs
      const fixedCosts = priceConfig.packagingCost + priceConfig.operationCost + priceConfig.otherCost;

      // Total Percentage Deductions (from Revenue)
      // Selling Price = (BaseCost + FixedCosts) / (1 - (Fee% + Ads% + Tax% + Profit%))
      // Example: 100k Cost, 10k Fixed. 10% Fee, 20% Profit.
      // Price = 110k / (1 - 0.3) = 110k / 0.7 = 157k

      const totalPercent = (priceConfig.feePercent + priceConfig.taxPercent + priceConfig.adsPercent + priceConfig.profitPercent) / 100;

      if (totalPercent >= 1) return 0; // Avoid division by zero or negative

      const suggestedPrice = (baseCost + fixedCosts) / (1 - totalPercent);
      return Math.ceil(suggestedPrice / 1000) * 1000; // Round to nearest 1000
